- [ ] Components with styles + tests in own directory
- [ ] Named exports (not default exports)
- [ ] Props interface exported alongside component
- [ ] Sub-components co-located in same directory
- [ ] No barrel files with 20+ re-exports

## React Code Standards

### Hooks over class components
```tsx
// WRONG: class component
class UserProfile extends React.Component<Props, State> {
  state = { user: null };
  componentDidMount() { fetchUser(this.props.id).then(u => this.setState({ user: u })); }
}

// CORRECT: functional + hooks
function UserProfile({ id }: { id: string }) {
  const { data: user, isLoading } = useQuery(['user', id], () => fetchUser(id));
  if (isLoading) return <Skeleton />;
  return <div>{user?.name}</div>;
}
```

### Single Responsibility
```tsx
// WRONG: god component
function Dashboard() {
  // fetches data, formats it, handles errors, renders nav, renders charts, handles export...
}

// CORRECT: each component does one thing
function Dashboard() {
  return (
    <DashboardLayout>
      <DashboardNav />
      <MetricsPanel />
      <RecentActivity />
    </DashboardLayout>
  );
}
```

### Context for shared state (no prop drilling)
```tsx
// Create typed context
const UserContext = React.createContext<User | null>(null);

export function UserProvider({ children }: { children: React.ReactNode }) {
  const [user, setUser] = React.useState<User | null>(null);
  return <UserContext.Provider value={user}>{children}</UserContext.Provider>;
}

export function useUser(): User | null {
  return React.useContext(UserContext);
}
```

### Extract custom hooks for stateful logic
```tsx
// Extract: don't cram state/effects into component body
function useUserSearch(initialQuery = '') {
  const [query, setQuery] = React.useState(initialQuery);
  const { data } = useQuery(['users', query], () => searchUsers(query), {
    enabled: query.length > 2
  });
  return { query, setQuery, results: data ?? [] };
}
```

### Checklist
- [ ] No class components (unless third-party error boundary)
- [ ] Components < 150 lines (extract if larger)
- [ ] Stateful logic in custom hooks
- [ ] No prop drilling > 2 levels (use context or state management)
- [ ] Named exports (easier to refactor than default)

