### Type hooks explicitly
```ts
// Return type makes contract clear
function usePagination(total: number, pageSize: number): {
  page: number;
  totalPages: number;
  nextPage: () => void;
  prevPage: () => void;
} {
  const [page, setPage] = React.useState(1);
  return {
    page,
    totalPages: Math.ceil(total / pageSize),
    nextPage: () => setPage(p => Math.min(p + 1, Math.ceil(total / pageSize))),
    prevPage: () => setPage(p => Math.max(p - 1, 1)),
  };
}
```

