## Code Splitting with React.lazy + Suspense

### Route-level splitting (most impactful)
```tsx
import React, { lazy, Suspense } from 'react';

// Each route becomes a separate chunk
const Dashboard = lazy(() => import('./features/dashboard/Dashboard'));
const Profile = lazy(() => import('./features/profile/Profile'));
const Settings = lazy(() => import('./features/settings/Settings'));

function App() {
  return (
    <Suspense fallback={<PageLoader />}>
      <Routes>
        <Route path="/dashboard" element={<Dashboard />} />
        <Route path="/profile" element={<Profile />} />
        <Route path="/settings" element={<Settings />} />
      </Routes>
    </Suspense>
  );
}
```

### Component-level splitting (heavy components)
```tsx
// Heavy data visualization — only load when rendered
const Charts = lazy(() => import('./Charts'));

function ReportsPage({ hasData }: { hasData: boolean }) {
  return (
    <div>
      <h1>Reports</h1>
      {hasData && (
